UPDATE challenges SET description_en = 'Dom Pérignon is the prestige cuvée of Moët & Chandon, named after the monk who helped perfect Champagne. Only vintage years are released; the wine offers complexity, finesse, and long ageing. Visit the cellars in Hautvillers and Épernay for the full story. Selected for our World 100 as the most iconic luxury Champagne and a benchmark for celebration.' WHERE category = 'drinks' AND title_en = 'Dom Perignon Champagne';

UPDATE challenges SET description_en = 'Krug Grande Cuvée is one of the most complex non-vintage Champagnes, blending 6 to 10 years of reserve wines. The house in Reims focuses on intensity and depth. It is a favourite of sommeliers and collectors. Selected for our World 100 as the pinnacle of non-vintage Champagne and a symbol of consistency and craft.' WHERE category = 'drinks' AND title_en = 'Krug Grande Cuvee Champagne';

UPDATE challenges SET description_en = 'Romanée-Conti is the world''s most expensive wine, from a 1.8-hectare Grand Cru in Burgundy''s Côte de Nuits. Pinot Noir from this vineyard defines elegance and terroir. Tiny production and legendary status make it almost impossible to taste outside auctions or top cellars. Selected for our World 100 as the ultimate expression of Burgundy and fine wine.' WHERE category = 'drinks' AND title_en = 'Romanee-Conti Grand Cru';

UPDATE challenges SET description_en = 'Pétrus is the legendary Pomerol estate, 100% Merlot on the right bank of Bordeaux. Tiny production and global demand make it one of the world''s most sought-after wines. The wine is rich, velvety, and ages for decades. Selected for our World 100 as the greatest Merlot-dominant wine and a symbol of Bordeaux luxury.' WHERE category = 'drinks' AND title_en = 'Petrus Pomerol';

UPDATE challenges SET description_en = 'Opus One is the Napa Valley joint venture between Robert Mondavi and Baron Philippe de Rothschild. The sculptural Oakville winery and the wine itself define California luxury Cabernet. Selected for our World 100 as the bridge between Bordeaux and Napa and an icon of New World fine wine.' WHERE category = 'drinks' AND title_en = 'Opus One, Napa Valley';

UPDATE challenges SET description_en = 'Screaming Eagle is the cult Napa Cabernet from Oakville, mailing-list only and among the most expensive California wines. The wine is powerful yet refined. Selected for our World 100 as the ultimate cult California wine and a symbol of Napa ambition.' WHERE category = 'drinks' AND title_en = 'Screaming Eagle Cabernet';

UPDATE challenges SET description_en = 'The Macallan 18 Year is a sherry-oak-matured Highland single malt from Easter Elchies House in Speyside. Rich, fruity, and complex, it defines luxury Scotch. Selected for our World 100 as one of the world''s most recognizable and collectible single malts.' WHERE category = 'drinks' AND title_en = 'The Macallan 18 Year';

UPDATE challenges SET description_en = 'Bowmore 25 Year Old is one of Islay''s oldest distilleries, offering peat smoke and sherry with Atlantic influence. The whisky is layered and long. Selected for our World 100 as a benchmark Islay malt and a symbol of Scottish island whisky.' WHERE category = 'drinks' AND title_en = 'Bowmore 25 Year Old';

UPDATE challenges SET description_en = 'Balvenie DoubleWood 17 Year is finished in American oak then European sherry casks in Dufftown, Speyside. The result is honey, fruit, and spice. Selected for our World 100 as an accessible yet premium example of cask finishing and Speyside craft.' WHERE category = 'drinks' AND title_en = 'Balvenie DoubleWood 17 Year';

UPDATE challenges SET description_en = 'Glenfiddich 21 Year Gran Reserva is finished in Caribbean rum casks at William Grant''s original Dufftown distillery. Tropical notes meet Speyside malt. Selected for our World 100 as an innovative and widely available premium single malt.' WHERE category = 'drinks' AND title_en = 'Glenfiddich 21 Year Gran Reserva';

UPDATE challenges SET description_en = 'Yamazaki 12 Year was the first Japanese single malt to gain global fame. Cherry blossom and Mizunara oak define its character. Suntory''s flagship distillery is near Kyoto. Selected for our World 100 as the gateway to Japanese whisky and a modern classic.' WHERE category = 'drinks' AND title_en = 'Yamazaki 12 Year Single Malt';

UPDATE challenges SET description_en = 'Hakushu 18 Year is from Suntory''s forest distillery in the Southern Alps. Herbal, alpine character with peat and fruit. Selected for our World 100 as the green, refined counterpart to Yamazaki and a symbol of Japanese whisky diversity.' WHERE category = 'drinks' AND title_en = 'Hakushu 18 Year Single Malt';

UPDATE challenges SET description_en = 'Hibiki 21 Year is a blended Japanese whisky in a 24-faceted decanter. Up to 21 malts and grains create harmony. Selected for our World 100 as the most elegant Japanese blend and a design and flavour icon.' WHERE category = 'drinks' AND title_en = 'Hibiki 21 Year Blended';

UPDATE challenges SET description_en = 'Nikka Yoichi Single Malt was founded by Masataka Taketsuru on the Hokkaido coast. Coal-fired stills and peat give a bold, Scottish-inspired profile. Selected for our World 100 as the soul of Japanese whisky history and a bridge to Scotch.' WHERE category = 'drinks' AND title_en = 'Nikka Yoichi Single Malt';

UPDATE challenges SET description_en = 'Redbreast 21 Year is a single pot still Irish whiskey from Midleton, Cork. Rich, spicy, and complex, it represents the best of Irish whiskey. Selected for our World 100 as the pinnacle of pot still whiskey and a symbol of Irish craft.' WHERE category = 'drinks' AND title_en = 'Redbreast 21 Year Single Pot Still';

UPDATE challenges SET description_en = 'Hennessy XO was the first XO cognac when created in 1870. Over 100 eaux-de-vie from Grande Champagne are blended. Visit Cognac for the tour. Selected for our World 100 as the world''s most iconic cognac and a benchmark for aged brandy.' WHERE category = 'drinks' AND title_en = 'Hennessy XO Cognac';

UPDATE challenges SET description_en = 'Remy Martin Louis XIII is aged up to 40 years in Tierçon decanters, blending 1,200 eaux-de-vie from Grande Champagne. The pinnacle of cognac. Selected for our World 100 as the most luxurious cognac and a symbol of time and craft.' WHERE category = 'drinks' AND title_en = 'Remy Martin Louis XIII';

UPDATE challenges SET description_en = 'Peruvian Pisco Sour is the national cocktail: pisco from the Ica Valley, lime, sugar, and key lime froth. Quebranta grape pisco is traditional. Try it in Lima and Ica. Selected for our World 100 as the defining South American cocktail and a symbol of Peruvian pride.' WHERE category = 'drinks' AND title_en = 'Peruvian Pisco Sour (original)';

UPDATE challenges SET description_en = 'Carmenère is Chile''s signature grape, saved from extinction and now thriving in the Maipo Valley. Concha y Toro Don Melchor and others show its depth. Selected for our World 100 as the grape that defines modern Chilean red wine and a comeback story.' WHERE category = 'drinks' AND title_en = 'Carmenere, Concha y Toro Don Melchor';

UPDATE challenges SET description_en = 'Achaval-Ferrer Quimera is a Mendoza icon from Luján de Cuyo, blending old-vine Malbec and other varieties. Rich and age-worthy. Selected for our World 100 as one of Argentina''s finest Malbecs and a symbol of Mendoza quality.' WHERE category = 'drinks' AND title_en = 'Achaval-Ferrer Malbec Quimera';

UPDATE challenges SET description_en = 'Guinness at St James''s Gate in Dublin is the source of the world''s most famous stout. Nitrogen pour, brewery tour, and history since 1759. Selected for our World 100 as the ultimate beer pilgrimage and a symbol of Irish identity.' WHERE category = 'drinks' AND title_en = 'Guinness Stout (at source)';

UPDATE challenges SET description_en = 'Dassai 23 is a junmai daiginjo with 23% rice polishing from Asahi Shuzo in Yamaguchi. Delicate, floral, and refined. Selected for our World 100 as the sake that introduced premium Japanese rice wine to the world.' WHERE category = 'drinks' AND title_en = 'Dassai 23 Junmai Daiginjo';

UPDATE challenges SET description_en = 'Moutai (Kweichow Moutai) is China''s most prestigious baijiu, sauce-aroma sorghum spirit from Guizhou at 53% ABV. State banquets and gift culture. Selected for our World 100 as the world''s most valuable spirit brand and a symbol of Chinese drinking culture.' WHERE category = 'drinks' AND title_en = 'Moutai (Kweichow Maotai)';

UPDATE challenges SET description_en = 'Weihenstephan Hefeweissbier is from the world''s oldest brewery (1040 AD) in Freising, Bavaria. Banana and clove from yeast; cloudy and refreshing. Selected for our World 100 as the benchmark German wheat beer and a living piece of brewing history.' WHERE category = 'drinks' AND title_en = 'Weihenstephan Hefeweissbier';

UPDATE challenges SET description_en = 'Pilsner Urquell is the world''s first pale lager, born in Pilsen in 1842. Golden, crisp, and historic. Selected for our World 100 as the beer that created a style and a pilgrimage to the Czech Republic.' WHERE category = 'drinks' AND title_en = 'Pilsner Urquell Original';

UPDATE challenges SET description_en = 'Westmalle Tripel is the defining Trappist tripel from the abbey at Malle, Belgium. Golden, strong, and complex. Selected for our World 100 as the benchmark abbey beer and a symbol of Belgian brewing.' WHERE category = 'drinks' AND title_en = 'Westmalle Tripel Trappist';

UPDATE challenges SET description_en = 'Inniskillin Vidal Icewine from Niagara is where Canadian icewine was legally pioneered: grapes picked at -8°C. Luscious, sweet, and iconic. Selected for our World 100 as the New World icewine standard and a Canadian treasure.' WHERE category = 'drinks' AND title_en = 'Inniskillin Vidal Icewine';

UPDATE challenges SET description_en = 'Pappy Van Winkle 23 Year is the holy grail of bourbon: wheated mashbill, Buffalo Trace, 23 years. Almost impossible to find at retail. Selected for our World 100 as the most sought-after American whiskey and a symbol of Kentucky craft.' WHERE category = 'drinks' AND title_en = 'Pappy Van Winkle 23 Year';

UPDATE challenges SET description_en = 'Pheasant Tears Rkatsiteli Qvevri is skin-contact orange wine from Georgia''s 8,000-year wine tradition, aged in clay qvevri. Amber, tannic, and ancient. Selected for our World 100 as the living link to the birth of wine and a symbol of Georgian viticulture.' WHERE category = 'drinks' AND title_en = 'Pheasant Tears Rkatsiteli Qvevri';

UPDATE challenges SET description_en = 'Amarula Cream Liqueur is made from the marula fruit, beloved by elephants in South Africa. Sweet, creamy, and iconic since 1989. Selected for our World 100 as Africa''s most famous liqueur and a taste of the bush.' WHERE category = 'drinks' AND title_en = 'Amarula Cream Liqueur';

UPDATE challenges SET description_en = 'Alvear Pedro Ximenez 1927 Solera is one of the world''s oldest PX soleras from Montilla-Moriles, Spain. Raisin, syrup, and infinite depth. Selected for our World 100 as the ultimate dessert wine experience and a piece of Spanish wine history.' WHERE category = 'drinks' AND title_en = 'Alvear Pedro Ximenez 1927 Solera';

UPDATE challenges SET description_en = 'Darroze 40 Year Armagnac is single-domaine vintage Bas-Armagnac from Gascony. One of the oldest eaux-de-vie in commercial release. Selected for our World 100 as the pinnacle of Armagnac and a taste of Gascon heritage.' WHERE category = 'drinks' AND title_en = 'Darroze Armagnac 40 Year';

UPDATE challenges SET description_en = 'Clase Azul Ultra Mezcal comes in a hand-painted ceramic decanter from Oaxaca. Ultra-premium blue agave and craft. Selected for our World 100 as the most luxurious expression of Mexican mezcal.' WHERE category = 'drinks' AND title_en = 'Clase Azul Ultra Mezcal';

UPDATE challenges SET description_en = 'Sassicaia DOC Bolgheri was the first Super Tuscan (1968), Cabernet in Tuscany''s coastal hills. It redefined Italian fine wine. Selected for our World 100 as the wine that broke the rules and created a category.' WHERE category = 'drinks' AND title_en = 'Sassicaia DOC Bolgheri';

UPDATE challenges SET description_en = 'Barolo Monfortino from Giacomo Conterno is the king of Barolo, Nebbiolo from Serralunga aged 8+ years in large botti. Selected for our World 100 as the greatest traditional Barolo and a symbol of Piedmont.' WHERE category = 'drinks' AND title_en = 'Barolo Monfortino Giacomo Conterno';

UPDATE challenges SET description_en = 'Vega Sicilia Unico is Spain''s legendary wine from Ribera del Duero: Tempranillo and Cabernet aged 10+ years. Selected for our World 100 as the benchmark Spanish luxury red.' WHERE category = 'drinks' AND title_en = 'Vega Sicilia Unico';

UPDATE challenges SET description_en = 'Graham 1963 Vintage Port is a legendary vintage from the Douro Valley: black fruit, molasses, and decades of ageing. Selected for our World 100 as one of the greatest vintage ports of the 20th century.' WHERE category = 'drinks' AND title_en = 'Graham 1963 Vintage Port';

UPDATE challenges SET description_en = 'Blandy 1920 Malmsey Madeira is century-old fortified wine from the volcanic island. Oxidation and time create unique depth. Selected for our World 100 as the ultimate aged Madeira experience.' WHERE category = 'drinks' AND title_en = 'Blandy 1920 Malmsey Madeira';

UPDATE challenges SET description_en = 'Tokaji Aszú 6 Puttonyos is Hungary''s noble sweet wine from botrytis grapes. Royal Tokaj and 400 years of history. Selected for our World 100 as the wine of kings and a Hungarian treasure.' WHERE category = 'drinks' AND title_en = 'Tokaji Aszu 6 Puttonyos';

UPDATE challenges SET description_en = 'Appleton Estate 50 Year is among the world''s oldest aged rum blends, from Nassau Valley copper pot stills in Jamaica. Selected for our World 100 as the pinnacle of aged Jamaican rum.' WHERE category = 'drinks' AND title_en = 'Appleton Estate 50 Year Jamaica Rum';

UPDATE challenges SET description_en = 'Mount Gay 1703 Rum from Barbados is the world''s oldest rum brand. Coral limestone water and Caribbean tradition. Selected for our World 100 as the birthplace of rum and a Bajan icon.' WHERE category = 'drinks' AND title_en = 'Mount Gay 1703 Rum';

UPDATE challenges SET description_en = 'Rhum Clément XO is AOC Martinique rhum agricole from fresh cane juice and column stills. The French Caribbean in a glass. Selected for our World 100 as the benchmark agricole rhum.' WHERE category = 'drinks' AND title_en = 'Rhum Clement XO Martinique';

UPDATE challenges SET description_en = 'Andong Soju is traditional Korean distilled soju from Andong, Gyeongbuk, at around 45% ABV. The original style before mass-produced diluted soju. Selected for our World 100 as the soul of Korean distilled spirit.' WHERE category = 'drinks' AND title_en = 'Andong Soju (Distilled Traditional)';

UPDATE challenges SET description_en = 'Premium Makgeolli is milky, slightly sparkling Korean rice wine. Artisanal producers in Gyeonggi and elsewhere revive old recipes. Selected for our World 100 as Korea''s oldest drink and a growing craft movement.' WHERE category = 'drinks' AND title_en = 'Premium Makgeolli (Korean Rice Wine)';

UPDATE challenges SET description_en = 'Wuliangye is a five-grain strong-aroma baijiu from Sichuan: sorghum, rice, corn, wheat, and glutinous rice. One of China''s top spirits. Selected for our World 100 as the counterpart to Moutai and a Sichuan icon.' WHERE category = 'drinks' AND title_en = 'Wuliangye Baijiu';

UPDATE challenges SET description_en = 'Amrut Fusion Single Malt blends Indian and Scottish barley at high altitude in Bangalore. Put Indian whisky on the world map. Selected for our World 100 as the pioneer of Indian single malt.' WHERE category = 'drinks' AND title_en = 'Amrut Fusion Single Malt';

UPDATE challenges SET description_en = 'Tej is ancient Ethiopian honey wine, flavoured with gesho (buckthorn). Sipped from traditional vessels in Addis Ababa tej bars. Selected for our World 100 as the drink of the Ethiopian highlands and a living tradition.' WHERE category = 'drinks' AND title_en = 'Tej Ethiopian Honey Wine';

UPDATE challenges SET description_en = 'Ararat 50 Year Nairi is Armenian brandy aged 50 years at the Yerevan Ararat Brandy Factory. Soviet-era legend and UNESCO-recognised craft. Selected for our World 100 as the pinnacle of Armenian brandy.' WHERE category = 'drinks' AND title_en = 'Ararat 50 Year Nairi Brandy';

UPDATE challenges SET description_en = 'Rochefort 10 is the darkest and most complex Trappist beer, a quadrupel from Rochefort Abbey in Belgium. Selected for our World 100 as the ultimate Belgian dark abbey beer.' WHERE category = 'drinks' AND title_en = 'Rochefort 10 Trappist';

UPDATE challenges SET description_en = 'Paulaner Oktoberfest Märzen is the original Munich Märzen lager: amber, malty, and the taste of the Oktoberfest tent. Selected for our World 100 as the beer of the world''s biggest beer festival.' WHERE category = 'drinks' AND title_en = 'Paulaner Oktoberfest Marzen';

UPDATE challenges SET description_en = 'Raki Yeni Raki is Turkey''s national anise spirit: double-distilled grape spirit that turns milky with water. Meze and fish companion. Selected for our World 100 as the soul of Turkish drinking culture.' WHERE category = 'drinks' AND title_en = 'Raki Yeni Raki';

UPDATE challenges SET description_en = 'Ouzo 12 from Plomari on Lesvos is one of Greece''s finest anise spirits. Ouzo and octopus by the sea. Selected for our World 100 as the taste of Greek summer and island life.' WHERE category = 'drinks' AND title_en = 'Ouzo 12';

UPDATE challenges SET description_en = 'Arak Château Ksara is Lebanese triple-distilled arak from the Bekaa Valley. Grape and anise, often with mezze. Selected for our World 100 as the benchmark Levantine arak.' WHERE category = 'drinks' AND title_en = 'Arak Chateau Ksara';

UPDATE challenges SET description_en = 'Elijah Craig Barrel Proof is Heaven Hill''s high-proof single-barrel bourbon from Kentucky. Uncut and bold. Selected for our World 100 as a modern American whiskey icon.' WHERE category = 'drinks' AND title_en = 'Elijah Craig Barrel Proof';

UPDATE challenges SET description_en = 'Nonino Grappa Monovitigno is single-variety pomace distillate from Friuli. The finest expression of Italian grappa. Selected for our World 100 as the grappa that elevated the category.' WHERE category = 'drinks' AND title_en = 'Nonino Grappa Monovitigno';
